import os, re, csv
from datetime import date, timedelta

REF = date(2025, 8, 12)
LOGDIR = '/app/logs'
SEVS = ['ERROR', 'WARNING', 'INFO']

periods = {
    'today': lambda d: d == REF,
    'last_7_days': lambda d: REF - timedelta(days=6) <= d <= REF,
    'last_30_days': lambda d: REF - timedelta(days=29) <= d <= REF,
    'month_to_date': lambda d: d.year == REF.year and d.month == REF.month and d <= REF,
    'total': lambda d: True,
}

counts = {p: {s: 0 for s in SEVS} for p in periods}
fname_re = re.compile(r'^(\d{4})-(\d{2})-(\d{2})_.*\.log$')
sev_re = re.compile(r'\[(ERROR|WARNING|INFO)\]')

for fn in os.listdir(LOGDIR):
    m = fname_re.match(fn)
    if not m:
        continue
    d = date(int(m.group(1)), int(m.group(2)), int(m.group(3)))
    with open(os.path.join(LOGDIR, fn)) as f:
        for line in f:
            sm = sev_re.search(line)
            if not sm:
                continue
            sev = sm.group(1)
            for p, pred in periods.items():
                if pred(d):
                    counts[p][sev] += 1

with open('/app/summary.csv', 'w', newline='') as f:
    w = csv.writer(f)
    w.writerow(['period', 'severity', 'count'])
    for p in ['today', 'last_7_days', 'last_30_days', 'month_to_date', 'total']:
        for s in SEVS:
            w.writerow([p, s, counts[p][s]])

print(open('/app/summary.csv').read())

